'use strict';

const { requestPackage } = require('./flaky-registry');

function sleep(ms) {
  return new Promise((resolve) => setTimeout(resolve, ms));
}

async function fetchPackageMeta(name, options = {}) {
  const retries = options.retries ?? 3;
  const backoffMs = options.backoffMs ?? 10;

  for (let attempt = 0; ; attempt += 1) {
    try {
      return await requestPackage(name);
    } catch (error) {
      if (error.code !== 'ECONNREFUSED' || attempt >= retries) {
        throw error;
      }
      await sleep(backoffMs * 2 ** attempt);
    }
  }
}

module.exports = { fetchPackageMeta };

